<?php declare(strict_types=1);session_start();require __DIR__.'/../includes/functions.php';
class BankAccount{public function __construct(private string $number,private string $holder,private float $balance){if($balance<0)throw new InvalidArgumentException('Số dư ban đầu không được âm.');}public function deposit(float $amount):void{if($amount<=0)throw new InvalidArgumentException('Số tiền nạp phải lớn hơn 0.');$this->balance+=$amount;}public function withdraw(float $amount):void{if($amount<=0)throw new InvalidArgumentException('Số tiền rút phải lớn hơn 0.');if($amount>$this->balance)throw new RuntimeException('Số dư không đủ.');$this->balance-=$amount;}public function data():array{return ['number'=>$this->number,'holder'=>$this->holder,'balance'=>$this->balance];}}
$_SESSION['account']??=['number'=>'00123456789','holder'=>'Nguyễn Văn A','balance'=>1000000.0];$a=$_SESSION['account'];$account=new BankAccount($a['number'],$a['holder'],(float)$a['balance']);$message='';$error='';if($_SERVER['REQUEST_METHOD']==='POST'){$action=(string)($_POST['action']??'');if($action==='reset'){$_SESSION['account']=['number'=>'00123456789','holder'=>'Nguyễn Văn A','balance'=>1000000.0];header('Location:index.php');exit;}try{$amount=filter_input(INPUT_POST,'amount',FILTER_VALIDATE_FLOAT);if($amount===false||$amount===null)throw new InvalidArgumentException('Số tiền không hợp lệ.');if($action==='deposit'){$account->deposit($amount);$message='Nạp tiền thành công.';}else{$account->withdraw($amount);$message='Rút tiền thành công.';}$_SESSION['account']=$account->data();}catch(Throwable $e){$error=$e->getMessage();}}$data=$account->data();$pageTitle='Bài 06 - Bank Account';$basePath='..';$current='bai06';require __DIR__.'/../includes/header.php';?>
<div class="crumb"><a href="../index.php">Trang chủ</a> / Bài 06</div><h1>Quản lý tài khoản ngân hàng</h1><p class="subtitle">Nạp tiền, rút tiền, kiểm tra số dư và lưu trạng thái bằng session.</p><?php if($message):?><div class="alert ok"><?=e($message)?></div><?php endif;?><?php if($error):?><div class="alert err"><?=e($error)?></div><?php endif;?><div class="two"><section class="card"><h2>Giao dịch</h2><form method="post"><div class="group"><label>Số tiền</label><input type="number" name="amount" min="1000" step="1000" value="<?=old('amount','100000')?>"></div><div class="actions"><button class="btn primary" name="action" value="deposit">Nạp tiền</button><button class="btn secondary" name="action" value="withdraw">Rút tiền</button><button class="btn danger" name="action" value="reset">Khôi phục</button></div></form></section><aside class="card"><h2>Thông tin tài khoản</h2><div class="item"><div class="muted">Số tài khoản</div><strong><?=e($data['number'])?></strong></div><div class="item"><div class="muted">Chủ tài khoản</div><strong><?=e($data['holder'])?></strong></div><div class="item"><div class="muted">Số dư</div><div class="stat"><?=e(money((float)$data['balance']))?></div></div></aside></div><?php require __DIR__.'/../includes/footer.php';?>
